import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { FirstbodyComponent } from './firstbody/firstbody.component';
import { HeaderComponent } from './header/header.component';
import { SecondbodyComponent } from './secondbody/secondbody.component';
import { ThirdbodyComponent } from './thirdbody/thirdbody.component';

const routes: Routes = [
  {path: '', redirectTo: 'header', pathMatch: 'full'},
  {path: 'firstbody', component:FirstbodyComponent},
  {path: 'secondbody', component:SecondbodyComponent},
  {path: 'thirdbody', component:ThirdbodyComponent}
];

@NgModule({
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule]
})
export class AppRoutingModule { }
